 226→    // ── Hoisted computedStarPositions for sharing across layers ──────
 227→    const computedStarPositions = useMemo(() => {
 228→        const map = new Map();
 229→        for (const post of postArray) {
 230→            const uid = post.users?.id ?? post.user_id;
 231→            const hashGal = userHomeCoords(uid);
 232→            const animGal = galaxyPositions.get(uid);
 233→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 234→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 235→            const pull = starPullOffsets.get(post.id);
 236→
 237→            const baseX = post.universe_x ?? post.display_x;
 238→            const baseY = post.universe_y ?? post.display_y;
 239→            if (baseX == null || baseY == null) continue;
 240→
 241→            let x = baseX + galDx + (pull?.dx ?? 0);
 242→            let y = baseY + galDy + (pull?.dy ?? 0);
 243→
 244→            map.set(post.id, { x, y });
 245→        }
 246→        return map;
 247→    }, [postArray, galaxyPositions, starPullOffsets]);
