 325→        };
 326→
 327→        resolveOwnGalaxyTarget();
 328→
 329→        return () => {
 330→            cancelled = true;
 331→        };
 332→    }, [userId]);
 333→
 334→    // One-time wormhole fetch on mount
 335→    useEffect(() => {
 336→        let cancelled = false;
 337→
 338→        const fetchWormholes = async () => {
 339→            try {
 340→                const { data, error } = await supabase.rpc('find_wormhole_pairs', {
 341→                    similarity_threshold: 0.7,
