 357→                }
 358→            }
 359→        };
 360→
 361→        fetchWormholes();
 362→        return () => { cancelled = true; };
 363→    }, []);
 364→
 365→    // Debounced fetch on camera/zoom change
 366→    useEffect(() => {
 367→        if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
 368→
 369→        fetchDebounceRef.current = setTimeout(async () => {
 370→            const bounds = getViewportBounds();
 371→            try {
 372→                const result = await getUniversePosts(
 373→                    bounds.minX,
 374→                    bounds.maxX,
 375→                    bounds.minY,
 376→                    bounds.maxY,
 377→                    200
 378→                );
 379→                if (result?.data) {
 380→                    setPosts(prev => {
 381→                        const next = new Map(prev);
 382→                        for (const post of result.data) {
 383→                            next.set(post.id, post);
 384→                        }
 385→                        return next;
 386→                    });
 387→                    if (userId && hasOwnPosts !== true) {
 388→                        const ownsAny = result.data.some(p =>
 389→                            (p.users?.id ?? p.user_id) === userId
 390→                        );
 391→                        if (ownsAny) setHasOwnPosts(true);
 392→                    }
 393→                }
 394→                // Keep server gravity data as fallback when embeddings are absent in payload.
 395→                setCentroids(Array.isArray(result?.centroids) ? result.centroids : []);
 396→                setGalaxyEdges(Array.isArray(result?.edges) ? result.edges : []);
 397→                setSimilarPairs(Array.isArray(result?.similarPairs) ? result.similarPairs : []);
 398→                setStarPulls(Array.isArray(result?.starPulls) ? result.starPulls : []);
 399→
 400→                // Fetch constellations for visible posts
 401→                if (result?.data?.length > 0) {
 402→                    const visibleIds = result.data.map(p => p.id);
 403→                    try {
 404→                        const constResult = await getViewportConstellations(visibleIds);
 405→                        if (constResult?.data) {
 406→                            setConstellations(constResult.data);
 407→                        }
 408→                    } catch (constErr) {
 409→                        console.warn('[universe] constellation fetch failed:', constErr?.message || constErr);
 410→                    }
 411→                }
 412→            } catch (err) {
 413→                console.error('Failed to fetch universe posts:', err);
 414→            } finally {
 415→                if (!initialFetchResolvedRef.current) {
 416→                    initialFetchResolvedRef.current = true;
 417→                    setIsInitialLoading(false);
 418→                }
 419→            }
 420→        }, 400);
 421→
 422→        return () => {
 423→            if (fetchDebounceRef.current) clearTimeout(fetchDebounceRef.current);
 424→        };
 425→    }, [camera, zoom, getViewportBounds, userId, hasOwnPosts]);
 426→
 427→    const handleStarClick = useCallback(async (post) => {
 428→        if (isFlying.current) return;
 429→
 430→        // Intercept for link mode
 431→        if (isLinkMode) {
 432→            setLinkModeError(null);
 433→            const result = await handleStarClickInLinkMode(post);
 434→            if (result?.error) {
 435→                setLinkModeError(result.error);
 436→                setTimeout(() => setLinkModeError(null), 3000);
 437→            }
 438→            return;
 439→        }
 440→
 441→        setSelectedPost(post);
 442→        setSelectedGalaxy(null);
 443→        setGalaxyProfile(null);
